class Solution:
    def matrixBlockSum(self, mat, k):
        m, n = len(mat), len(mat[0])
        ans = [[0] * n for _ in range(m)]
        for i in range(m):
            for j in range(n):
                total = 0
                for r in range(max(0, i - k), min(m, i + k + 1)):
                    for c in range(max(0, j - k), min(n, j + k + 1)):
                        total += mat[r][c]
                ans[i][j] = total
        return ans

